export const getUgImportTabUrl = () => {




  return `/api/ug/import`
}

/**
 * @summary Import a UG tab into the song library
 */
export const ugImportTab = async (ugImportInput: UgImportInput, options?: RequestInit): Promise<Song> => {

  return customFetch<Song>(getUgImportTabUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      ugImportInput,)
  }
);}




export const getUgImportTabMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof ugImportTab>>, TError,{data: BodyType<UgImportInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof ugImportTab>>, TError,{data: BodyType<UgImportInput>}, TContext> => {

const mutationKey = ['ugImportTab'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof ugImportTab>>, {data: BodyType<UgImportInput>}> = (props) => {
          const {data} = props ?? {};

          return  ugImportTab(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type UgImportTabMutationResult = NonNullable<Awaited<ReturnType<typeof ugImportTab>>>
    export type UgImportTabMutationBody = BodyType<UgImportInput>
    export type UgImportTabMutationError = ErrorType<unknown>

    /**
 * @summary Import a UG tab into the song library
 */
export const useUgImportTab = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof ugImportTab>>, TError,{data: BodyType<UgImportInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof ugImportTab>>,
        TError,
        {data: BodyType<UgImportInput>},
        TContext
      > => {
      return useMutation(getUgImportTabMutationOptions(options));
    }

